const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }
let custom = pick(i['Custom topic'], i.customTopic);
let drop = pick(i['Topic'], i.topic); if(/^custom/i.test(drop)) drop='';
let t = pick(custom, drop, i.query, i.text);
t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if (!t) t = ($env.DEFAULT_AWARENESS_TOPIC || 'phishing');
return [{ json: { topic:t, audience:(pick(i['Audience'],i.audience)||'All staff'), tone:(pick(i['Tone'],i.tone)||'Friendly'), questions:pick(i['Questions'],i.questions), difficulty:pick(i['Difficulty'],i.difficulty), duration:pick(i['Duration'],i.duration), level:pick(i['Audience level'],i.level), numTips:pick(i['Number of tips'],i.numTips), date:new Date().toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString() } }];

