={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-sonnet-4-6' }}",
  "max_tokens": 2000,
  "system": "You are a security-awareness content designer. For the given topic, produce a SINGLE valid JSON object for an awareness POSTER and a one-page EXPLAINER aimed at general, non-technical staff. Keys: topic; poster {headline (max 6 words, punchy), tagline (one short line), points (3-5 short imperative do/dont bullets, max ~8 words each)}; explainer {title, intro (2 sentences), why (2 sentences on why it matters to the organisation and the individual), redFlags (4-6 short warning signs), dos (4-6 short good practices), donts (3-5 short things to avoid)}. Use plain, encouraging, action-oriented language; no jargon, no fear-mongering. Tailor the language, examples and difficulty to the stated Audience and Tone, and honour any stated number of questions, difficulty, duration, seniority or number of tips. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('Create awareness poster and explainer content for the topic: ' + ($json.topic || 'phishing') + '. Audience: ' + ($json.audience||'All staff') + '. Tone: ' + ($json.tone||'Friendly') + ($json.questions?('. Number of questions: '+$json.questions):'') + ($json.difficulty?('. Difficulty: '+$json.difficulty):'') + ($json.duration?('. Duration: '+$json.duration):'') + ($json.level?('. Audience seniority: '+$json.level):'') + ($json.numTips?('. Number of tips: '+$json.numTips):'')) }} } ]
}

