const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
const imagePrompt = 'Clean professional security-awareness poster background illustration about ' + r.topic +
 '. Modern flat vector style, calm corporate deep-blue and teal palette, abstract security icons (shield, padlock, envelope, fish-hook), plenty of empty space in the upper area for a headline. NO text, NO words, NO letters, NO logos, NO faces, NO watermark.';
return [{ json: { data: data, topic: r.topic, date: r.date, client: r.client, imagePrompt: imagePrompt, markdown: raw } }];

const d = $json.data || {};
const topic = $json.topic || 'Security Awareness';
const date = $json.date || new Date().toISOString().slice(0,10);
const client = ($json.client || '').toString();
const fs = require('fs');
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function ord(n){ var s=['th','st','nd','rd'],v=n%100; return n+(s[(v-20)%10]||s[v]||s[0]); }
function pretty(x){ try{ var p=x.split('-'); var dt=new Date(+p[0],+p[1]-1,+p[2]); var M=['January','February','March','April','May','June','July','August','September','October','November','December']; return M[dt.getMonth()]+' '+ord(dt.getDate())+' '+dt.getFullYear(); }catch(e){ return x; } }
function fileUri(b){ var t=[['/config/branding/'+b+'.png','image/png'],['/config/branding/'+b+'.jpg','image/jpeg']]; for(var i=0;i<t.length;i++){ try{ return 'data:'+t[i][1]+';base64,'+fs.readFileSync(t[i][0]).toString('base64'); }catch(e){} } return ''; }
let img=''; try { var b64=$('Generate Poster Image').first().json.data[0].b64_json; if(b64) img='data:image/png;base64,'+b64; } catch(e){ img=''; }
if(!img) img = fileUri('awareness-poster') || fileUri('cover') || '';
const poster = d.poster || {};
const ex = d.explainer || {};
const byline = client ? ('Prepared for ' + client) : 'Security Awareness';
const points = (poster.points||[]).slice(0,5);
function li(x){ return '<li>'+esc(x)+'</li>'; }
const CSS = '@page{margin:0} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,"Segoe UI",Arial,sans-serif} '
 + '.poster{height:100vh;page-break-after:always;position:relative;background:#0E2233;overflow:hidden;color:#fff} '
 + '.poster .bg{position:absolute;top:0;left:0;right:0;bottom:0;background-size:cover;background-position:center} '
 + '.poster .ov{position:absolute;top:0;left:0;right:0;bottom:0;background:linear-gradient(135deg,rgba(8,20,32,.93),rgba(8,20,32,.5) 58%,rgba(8,20,32,.2))} '
 + '.poster .pc{position:absolute;left:54px;right:54px;top:66px} '
 + '.poster .kick{color:#5FD0C0;letter-spacing:3px;font-weight:800;font-size:14px;text-transform:uppercase} '
 + '.poster h1{font-size:56px;line-height:1.03;margin:14px 0 12px;font-weight:800} '
 + '.poster .tag{font-size:20px;color:#CDE7F0;max-width:74%;line-height:1.4} '
 + '.poster ul{position:absolute;left:54px;right:54px;bottom:118px;list-style:none;padding:0;margin:0} '
 + '.poster li{font-size:21px;line-height:1.45;padding:11px 0 11px 40px;border-top:1px solid rgba(255,255,255,.16);position:relative} '
 + '.poster li:before{content:"\\2713";position:absolute;left:4px;top:11px;color:#5FD0C0;font-weight:800} '
 + '.poster .foot{position:absolute;left:54px;right:54px;bottom:50px;color:#9fb6c2;font-size:14px;letter-spacing:1px;border-top:2px solid #5FD0C0;padding-top:12px;display:flex;justify-content:space-between} '
 + '.ex{padding:46px 54px;color:#11151c} '
 + '.ex .kick{color:#0E7C86;letter-spacing:2px;font-weight:800;font-size:12px;text-transform:uppercase} '
 + '.ex h2{font-family:Georgia,serif;font-size:30px;color:#0E2233;margin:6px 0 14px;border-bottom:3px solid #0E7C86;padding-bottom:10px} '
 + '.ex p{font-size:15px;line-height:1.62;color:#2b3340;margin:0 0 10px} '
 + '.ex h3{font-size:13px;letter-spacing:1.5px;text-transform:uppercase;color:#0E2233;margin:20px 0 8px} '
 + '.ex .cols{display:flex;gap:26px} .ex .col{flex:1} '
 + '.ex ul{margin:6px 0;padding-left:20px} .ex li{font-size:14px;line-height:1.55;margin:6px 0;color:#2b3340} '
 + '.ex .rf li{color:#8a1f1f} .ex .do li{color:#1E6B3A} '
 + '.ex .foot{margin-top:28px;border-top:1px solid #E2E6EC;padding-top:12px;color:#5A6472;font-size:12px;display:flex;justify-content:space-between} ';
const posterHtml = '<div class="poster">'
 + (img?'<div class="bg" style="background-image:url('+img+')"></div>':'')
 + '<div class="ov"></div>'
 + '<div class="pc"><div class="kick">Security Awareness</div><h1>'+esc(poster.headline||topic)+'</h1>'+(poster.tagline?'<div class="tag">'+esc(poster.tagline)+'</div>':'')+'</div>'
 + (points.length?('<ul>'+points.map(li).join('')+'</ul>'):'')
 + '<div class="foot"><span>'+esc(byline)+'</span><span>'+esc(pretty(date))+'</span></div></div>';
function list(arr,cls){ if(!arr||!arr.length)return''; return '<ul class="'+cls+'">'+arr.map(li).join('')+'</ul>'; }
const exHtml = '<div class="ex"><div class="kick">Explainer</div><h2>'+esc(ex.title||('Understanding '+topic))+'</h2>'
 + (ex.intro?'<p>'+esc(ex.intro)+'</p>':'')
 + (ex.why?'<h3>Why it matters</h3><p>'+esc(ex.why)+'</p>':'')
 + (ex.redFlags&&ex.redFlags.length?'<h3>Red flags to watch for</h3>'+list(ex.redFlags,'rf'):'')
 + '<div class="cols"><div class="col"><h3>Do</h3>'+list(ex.dos,'do')+'</div><div class="col"><h3>Don’t</h3>'+list(ex.donts,'rf')+'</div></div>'
 + '<div class="foot"><span>'+esc(byline)+' · AI-generated — review before distribution</span><span>'+esc(pretty(date))+'</span></div></div>';
const html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+posterHtml+exHtml+'</body></html>';
const fileSafe = topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40) || 'asset';
return [{ json: { html: html, topic: topic, date: date, fileSafe: fileSafe } }];

const html = $json.html || '';
return [{ json: { topic: $json.topic, date: $json.date, fileSafe: $json.fileSafe },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType: 'text/html', fileName: 'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/posters';
const name = 'poster-' + (meta.fileSafe || 'asset') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
